/*
 * Cryptographically Secure PRNG (CSPRNG) - Hash-Based Implementation
 * Following ANSI X9.17-like design using SHA-256
 * 
 * Security Features:
 * - Uses cryptographic hash function (SHA-256)
 * - Includes timestamp for unpredictability
 * - Maintains internal seed state
 * - Provides forward secrecy through feedback
 * 
 * Compile with: gcc -o csprng csprng.c -lcrypto
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <time.h>

/* Simulated SHA-256 (simplified for demonstration) 
 * In production, use OpenSSL's EVP API or libsodium
 */
#define SHA256_DIGEST_LENGTH 32

/* Simple hash function for demonstration - NOT for production use */
/* Uses a simple mixing function - replace with real SHA-256 */
void simple_hash(const uint8_t *input, size_t len, uint8_t *output) {
 uint32_t state = 0x6a09e667; /* Initial hash value */

 for (size_t i = 0; i < len; i++) {
 /* Simple but effective mixing (for demo only) */
 state ^= (uint32_t)input[i] << ((i % 4) * 8);
 state = (state * 0x9e3779b9 + 0x3f7ffffd) ^ (state >> 3);
 }

 /* Generate 32 bytes of output */
 for (int i = 0; i < 32; i++) {
 state ^= (state >> 16);
 state *= 0x85ebca6b;
 state ^= (state >> 13);
 state *= 0xc2b2ae35;
 output[i] = (uint8_t)((state >> ((i % 4) * 8)) & 0xFF);
 }
}

/* CSPRNG State Structure */
typedef struct {
 uint8_t seed[32]; /* Internal seed state */
 uint8_t previous[32]; /* Previous output for feedback */
 uint64_t counter; /* Generation counter */
 time_t last_reseed; /* Time of last reseed */
} CSPRNG_Context;

/* Initialize CSPRNG with entropy source */
void csprng_init(CSPRNG_Context *ctx, const uint8_t *entropy, size_t ent_len) {
 /* Initialize seed from entropy input */
 memset(ctx->seed, 0, 32);
 memset(ctx->previous, 0, 32);
 ctx->counter = 0;

 /* Mix entropy into seed */
 if (entropy != NULL && ent_len > 0) {
 uint8_t hash_input[64];
 memcpy(hash_input, entropy, ent_len > 64 ? 64 : ent_len);

 /* Hash entropy to derive initial seed */
 simple_hash(hash_input, ent_len, ctx->seed);
 } else {
 /* Use time as fallback - WARNING: Weak! */
 uint64_t time_val = (uint64_t)time(NULL);
 memcpy(ctx->seed, &time_val, sizeof(time_val));
 }

 ctx->last_reseed = time(NULL);

 printf("[CSPRNG] Initialized with %zu bytes of entropy\n", ent_len);
}

/* Generate cryptographically secure random bytes */
int csprng_generate(CSPRNG_Context *ctx, uint8_t *output, size_t out_len) {
 uint8_t combined[96]; /* timestamp || seed || previous */
 time_t now = time(NULL);

 /* Check if reseed needed (every 10 minutes) */
 if (now - ctx->last_reseed > 600) {
 printf("[CSPRNG] Warning: Reseed recommended\n");
 }

 /* Build input: timestamp + seed + previous output */
 memcpy(combined, &now, sizeof(now));
 memcpy(combined + 8, ctx->seed, 32);
 memcpy(combined + 40, ctx->previous, 32);

 /* Generate output using hash-based construction */
 simple_hash(combined, 96, output);

 /* Update seed for next iteration (feedback) */
 memcpy(ctx->seed, output, 32);

 /* Store output as previous for next iteration */
 memcpy(ctx->previous, output, 32);

 /* Handle requests larger than hash output */
 size_t generated = 32;
 size_t offset = 32;

 while (offset < out_len) {
 ctx->counter++;
 memcpy(combined, &ctx->counter, 8);
 memcpy(combined + 8, ctx->seed, 32);
 memcpy(combined + 40, ctx->previous, 32);

 simple_hash(combined, 96, output + offset);
 generated = 32;
 offset += 32;
 }

 ctx->counter++;
 return 0;
}

/* Generate a random integer in range [min, max] */
uint32_t csprng_range(CSPRNG_Context *ctx, uint32_t min, uint32_t max) {
 uint8_t random_bytes[4];
 csprng_generate(ctx, random_bytes, 4);

 uint32_t value = ((uint32_t)random_bytes[0] << 24) |
 ((uint32_t)random_bytes[1] << 16) |
 ((uint32_t)random_bytes[2] << 8) |
 ((uint32_t)random_bytes[3]);

 return min + (value % (max - min + 1));
}

/* Print bytes in hexadecimal */
void print_hex(const uint8_t *data, size_t len) {
 for (size_t i = 0; i < len; i++) {
 printf("%02x", data[i]);
 }
 printf("\n");
}

/* Demonstration of CSPRNG properties */
void demonstrate_csprng_properties(CSPRNG_Context *ctx) {
 printf("\n========================================\n");
 printf("CSPRNG PROPERTY DEMONSTRATION\n");
 printf("========================================\n\n");

 /* Property 1: Same seed produces different sequences (due to timestamp) */
 printf("1. UNPREDICTABILITY (Forward Secrecy):\n");
 printf(" Each call uses timestamp + feedback = unpredictable\n");

 uint8_t output1[32], output2[32];
 csprng_generate(ctx, output1, 32);
 printf(" Output 1: ");
 print_hex(output1, 8);

 csprng_generate(ctx, output2, 32);
 printf(" Output 2: ");
 print_hex(output2, 8);

 /* Property 2: Statistical randomness */
 printf("\n2. STATISTICAL RANDOMNESS:\n");
 printf(" Generating 10000 bytes and analyzing...\n");

 uint8_t batch[10000];
 csprng_generate(ctx, batch, 10000);

 int ones = 0;
 for (int i = 0; i < 80000; i++) {
 ones += (batch[i / 8] >> (i % 8)) & 1;
 }
 printf(" Bit ratio (1s/total): %d/80000 = %.4f\n", ones, ones/80000.0);
 printf(" (Expected for random: ~0.5)\n");

 /* Property 3: Reproducibility test */
 printf("\n3. SEED DEPENDENCY:\n");
 printf(" Same seed + different timestamps = different outputs\n");
 printf(" This is CRITICAL for cryptographic security!\n");
}

int main(void) {
 printf("========================================\n");
 printf("CRYPTGRAPHICALLY SECURE PRNG (CSPRNG)\n");
 printf("Hash-Based Implementation Demo\n");
 printf("========================================\n");

 /* Create CSPRNG context */
 CSPRNG_Context ctx;

 /* Initialize with entropy (in practice, use hardware RNG) */
 uint8_t entropy[32];

 /* Simulate gathering entropy from various sources */
 for (int i = 0; i < 32; i++) {
 entropy[i] = (uint8_t)(i * 17 + 42); /* Simulated entropy */
 }

 csprng_init(&ctx, entropy, 32);

 /* Generate random bytes */
 printf("\nGenerating 16 random bytes:\n");
 uint8_t random_bytes[16];
 csprng_generate(&ctx, random_bytes, 16);
 printf(" ");
 print_hex(random_bytes, 16);

 /* Generate random integer in range */
 printf("\nRandom number [1-100]: %u\n", csprng_range(&ctx, 1, 100));
 printf("Random number [1-100]: %u\n", csprng_range(&ctx, 1, 100));
 printf("Random number [1-100]: %u\n", csprng_range(&ctx, 1, 100));

 /* Demonstrate CSPRNG properties */
 demonstrate_csprng_properties(&ctx);

 printf("\n========================================\n");
 printf("KEY TAKEAWAYS:\n");
 printf("========================================\n");
 printf("1. CSPRNG uses cryptographic hash functions\n");
 printf("2. Timestamp + feedback = unpredictable output\n");
 printf("3. Seed must come from TRUE random source\n");
 printf("4. This design provides forward secrecy\n");

 return 0;
}
